group relative rounded-[24px] max-md:rounded-2xl overflow-hidden transition-all duration-700 ease-[0.16,1,0.3,1] shadow-sm hover:shadow-xl hover:shadow-black/5 dark:hover:shadow-white/5 ${opacityClass} ${
                  isFeatured
                    ? "col-span-2 sm:col-span-2 lg:col-span-6 lg:row-span-2 h-[350px] md:h-[500px] lg:h-[520px]"
                    : "col-span-1 sm:col-span-1 lg:col-span-3 lg:row-span-1 h-[200px] lg:h-[248px]"
                }

fixed top-0 z-50 w-full transition-all duration-700 max-md:h-[60px] max-md:flex max-md:items-center ${
        scrolled
          ? "bg-[color:var(--ivory)]/80 backdrop-blur-md shadow-sm border-b border-[color:var(--border)] py-3 max-md:py-0"
          : "bg-transparent py-6 max-md:py-0"
      }

relative z-10 flex md:items-center gap-3 px-4 py-3 max-md:p-4 max-md:flex-col max-md:items-start max-md:justify-center rounded-xl max-md:rounded-2xl transition-all duration-300 max-md:border ${
                        isActuallyActive
                          ? "text-[color:var(--gold)] max-md:bg-[color:var(--gold)]/5 max-md:border-[color:var(--gold)]/30"
                          : "text-[color:var(--foreground)] hover:text-[color:var(--gold)] max-md:bg-[color:var(--background)] max-md:border-[color:var(--border)] max-md:shadow-sm"
                      }
